def get_translations_for_key(key):
    """Get translations for a key. Returns list of 18 translations."""
    # Check if it's a common word with known translations
    if key in COMMON_TRANSLATIONS:
        return COMMON_TRANSLATIONS[key]

    # Check English map for underscore-keyed strings
    if key in ENGLISH_MAP:
        return [ENGLISH_MAP[key]] + [''] * 17

    # For keys that are English text (no underscore), use key as English
    en_text = key

    # Return English in first position, rest empty (fallback to English)
    return [en_text] + [''] * 17

# Read existing CSV translations
existing = {}
try:
    with open('localization.csv', 'r', encoding='utf-8') as f:
        reader = csv.reader(f)
        header = next(reader)
        for row in reader:
            if row and len(row) > 1:
                existing[row[0]] = row[1:]
except:
    pass

# Read all keys from codebase
with open('all_keys.txt', 'r', encoding='utf-8') as f:
    all_keys = sorted([line.strip() for line in f if line.strip()])

# Build complete CSV
out_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'localization.csv')
with open(out_path, 'w', encoding='utf-8', newline='') as f:
    writer = csv.writer(f)
    writer.writerow(['Id'] + LANGS)

    translated_count = 0
    english_only_count = 0

    for key in all_keys:
        # Always try to get translations from COMMON_TRANSLATIONS first
        # Look up by English text (from ENGLISH_MAP or the key itself)
        en_text = ENGLISH_MAP.get(key, key)
        common_trans = COMMON_TRANSLATIONS.get(en_text)

        if common_trans:
            # Full translations available
            row = list(common_trans)
            while len(row) < 18:
                row.append('')
            writer.writerow([key] + row[:18])
            translated_count += 1
        else:
            # No translations — use English only
            row = [en_text] + [''] * 17
            writer.writerow([key] + row[:18])
            english_only_count += 1

print(f'Generated {len(all_keys)} entries to {out_path}')
print(f'  - {translated_count} with full translations')
print(f'  - {english_only_count} with English only')
